# agentic_I2 skeptic-crosscheck · S07-T4-A-E2
def token_jaccard(a, b):
    A, B = set(a.casefold().split()), set(b.casefold().split())
    if not A and not B:
        return 1.0
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)
print(round(token_jaccard('Juan Perez', 'Juan P Perez'), 3))

